B.alL=new A.l([B.d,"Treats the next played deck card as a Joker, allowing you to capture any unmatched card from the field.",B.e,"\u6b21\u306b\u51fa\u3059\u5c71\u672d\u306e\u30ab\u30fc\u30c9\u3092\u30b8\u30e7\u30fc\u30ab\u30fc\u3068\u3057\u3066\u6271\u3044\u3001\u5834\u306e\u597d\u304d\u306a\u30ab\u30fc\u30c9\u30921\u679a\u78ba\u5b9f\u306b\u7372\u5f97\u3057\u307e\u3059\u3002",B.f,"\u5c06\u4e0b\u4e00\u5f20\u6253\u51fa\u7684\u724c\u5e93\u724c\u89c6\u4e3a\u9b3c\u724c\uff0c\u8ba9\u4f60\u80fd\u593a\u53d6\u573a\u4e0a\u4e00\u5f20\u4efb\u610f\u5361\u724c\u3002",B.h,"\u5c07\u4e0b\u4e00\u5f35\u6253\u51fa\u7684\u724c\u5eab\u724c\u8996\u70ba\u9b3c\u724c\uff0c\u8b93\u4f60\u80fd\u596a\u53d6\u5834\u4e0a\u4e00\u5f35\u4efb\u610f\u5361\u724c\u3002",B.i,"Trata la siguiente carta del mazo como un Comod\xedn, permitiendo capturar cualquier carta sin pareja del campo.",B.j,"Traite la prochaine carte du paquet comme un Joker, permettant de capturer n'importe quelle carte non associ\xe9e du terrain.",B.k,"Behandelt die n\xe4chste Stapelkarte als Joker und erm\xf6glicht es, jede ungepaarte Karte vom Feld zu erbeuten.",B.l,"Trata a pr\xf3xima carta do baralho como Coringa, permitindo capturar qualquer carta sem par do campo.",B.m,"\u0e17\u0e33\u0e43\u0e2b\u0e49\u0e44\u0e1e\u0e48\u0e43\u0e1a\u0e16\u0e31\u0e14\u0e44\u0e1b\u0e08\u0e32\u0e01\u0e01\u0e2d\u0e07\u0e40\u0e1b\u0e47\u0e19\u0e42\u0e08\u0e4a\u0e01\u0e40\u0e01\u0e2d\u0e23\u0e4c \u0e22\u0e36\u0e14\u0e44\u0e1e\u0e48\u0e43\u0e14\u0e01\u0e47\u0e44\u0e14\u0e49\u0e17\u0e35\u0e48\u0e44\u0e21\u0e48\u0e21\u0e35\u0e04\u0e39\u0e48\u0e08\u0e32\u0e01\u0e2a\u0e19\u0e32\u0e21"],t.C)
B.akM=new A.l([B.d,"Forcefully steal one specific card from the opponent's captured area. (Once per game)",B.e,"\u76f8\u624b\u304c\u7372\u5f97\u3057\u305f\u30ab\u30fc\u30c9\u306e\u4e2d\u304b\u3089\u3001\u597d\u304d\u306a\u30ab\u30fc\u30c9\u30921\u679a\u5f37\u5236\u7684\u306b\u596a\u3044\u53d6\u308a\u307e\u3059\u3002(1\u30b2\u30fc\u30e01\u56de)",B.f,"\u5f3a\u5236\u4ece\u5bf9\u624b\u5f97\u5206\u533a\u593a\u53d6\u7279\u5b9a\u7684\u4e00\u5f20\u724c\u3002\uff08\u6bcf\u5c40\u9650\u4e00\u6b21\uff09",B.h,"\u5f37\u5236\u5f9e\u5c0d\u624b\u5f97\u5206\u5340\u596a\u53d6\u7279\u5b9a\u7684\u4e00\u5f35\u724c\u3002\uff08\u6bcf\u5c40\u9650\u4e00\u6b21\uff09",B.i,"Roba una carta espec\xedfica del \xe1rea de captura del oponente. (Una vez por juego)",B.j,"Vole de force une carte sp\xe9cifique de la zone de capture de l'adversaire. (Une fois par partie)",B.k,"Stiehlt eine bestimmte Karte aus dem Gewinnbereich des Gegners. (Einmal pro Spiel)",B.l,"Rouba uma carta espec\xedfica da \xe1rea de captura do oponente. (Uma vez por jogo)",B.m,"\u0e02\u0e42\u0e21\u0e22\u0e44\u0e1e\u0e48\u0e43\u0e1a\u0e40\u0e09\u0e1e\u0e32\u0e30\u0e08\u0e32\u0e01\u0e1e\u0e37\u0e49\u0e19\u0e17\u0e35\u0e48\u0e22\u0e36\u0e14\u0e02\u0e2d\u0e07\u0e04\u0e39\u0e48\u0e15\u0e48\u0e2d\u0e2a\u0e39\u0e49 (\u0e04\u0e23\u0e31\u0e49\u0e07\u0e40\u0e14\u0e35\u0e22\u0e27\u0e15\u0e48\u0e2d\u0e40\u0e01\u0e21)"],t.C)
B.akI=new A.l([B.d,"Collect all cards on the field, shuffle them back into the deck, and redeploy them.",B.e,"\u5834\u306b\u51fa\u3066\u3044\u308b\u30ab\u30fc\u30c9\u3092\u3059\u3079\u3066\u56de\u53ce\u3057\u3001\u5c71\u672d\u3068\u6df7\u305c\u3066\u518d\u914d\u7f6e\u3057\u307e\u3059\u3002",B.f,"\u5c06\u573a\u4e0a\u6240\u6709\u5361\u724c\u6536\u56de\uff0c\u4e0e\u724c\u5e93\u91cd\u65b0\u6d17\u724c\u5e76\u518d\u6b21\u5e03\u9635\u3002",B.h,"\u5c07\u5834\u4e0a\u6240\u6709\u5361\u724c\u6536\u56de\uff0c\u8207\u724c\u5eab\u91cd\u65b0\u6d17\u724c\u4e26\u518d\u6b21\u5e03\u9663\u3002",B.i,"Recoge todas las cartas del campo, las mezcla en el mazo y las redistribuye.",B.j,"Collecte toutes les cartes du terrain, les m\xe9lange dans le paquet et les red\xe9ploie.",B.k,"Sammelt alle Karten vom Feld ein, mischt sie zur\xfcck in den Stapel und verteilt sie neu.",B.l,"Recolhe todas as cartas do campo, embaralha de volta no baralho e redistribui.",B.m,"\u0e40\u0e01\u0e47\u0e1a\u0e44\u0e1e\u0e48\u0e17\u0e31\u0e49\u0e07\u0e2b\u0e21\u0e14\u0e1a\u0e19\u0e2a\u0e19\u0e32\u0e21 \u0e2a\u0e31\u0e1a\u0e23\u0e27\u0e21\u0e01\u0e31\u0e1a\u0e01\u0e2d\u0e07\u0e44\u0e1e\u0e48\u0e41\u0e25\u0e49\u0e27\u0e27\u0e32\u0e07\u0e43\u0e2b\u0e21\u0e48"],t.C)
B.al4=new A.l([B.d,"Significantly increases the chance of Gwang (Bright) cards appearing in the initial deal.",B.e,"\u6700\u521d\u306e\u30ab\u30fc\u30c9\u914d\u5e03\u6642\u3001\u624b\u672d\u3084\u5834\u306b\u5149(\u5149\u672d)\u304c\u914d\u7f6e\u3055\u308c\u308b\u78ba\u7387\u304c\u5927\u5e45\u306b\u5897\u52a0\u3057\u307e\u3059\u3002",B.f,"\u5f00\u5c40\u53d1\u724c\u65f6\uff0c\u5927\u5e45\u589e\u52a0\u5149\u724c\u51fa\u73b0\u5728\u624b\u724c\u6216\u573a\u4e0a\u7684\u51e0\u7387\u3002",B.h,"\u958b\u5c40\u767c\u724c\u6642\uff0c\u5927\u5e45\u589e\u52a0\u5149\u724c\u51fa\u73fe\u5728\u624b\u724c\u6216\u5834\u4e0a\u7684\u6a5f\u7387\u3002",B.i,"Aumenta significativamente la probabilidad de que aparezcan cartas Gwang (Brillantes) en el reparto inicial.",B.j,"Augmente consid\xe9rablement la chance d'apparition des cartes Gwang (Lumi\xe8re) lors de la distribution initiale.",B.k,"Erh\xf6ht deutlich die Chance, dass Gwang (Licht)-Karten beim ersten Austeilen erscheinen.",B.l,"Aumenta significativamente a chance de cartas Gwang (Brilhantes) aparecerem na distribui\xe7\xe3o inicial.",B.m,"\u0e40\u0e1e\u0e34\u0e48\u0e21\u0e42\u0e2d\u0e01\u0e32\u0e2a\u0e2d\u0e22\u0e48\u0e32\u0e07\u0e21\u0e32\u0e01\u0e17\u0e35\u0e48\u0e44\u0e1e\u0e48\u0e01\u0e27\u0e31\u0e07 (\u0e2a\u0e27\u0e48\u0e32\u0e07) \u0e08\u0e30\u0e1b\u0e23\u0e32\u0e01\u0e0f\u0e43\u0e19\u0e01\u0e32\u0e23\u0e41\u0e08\u0e01\u0e44\u0e1e\u0e48\u0e40\u0e23\u0e34\u0e48\u0e21\u0e15\u0e49\u0e19"],t.C)
B.alo=new A.l([B.d,"Prevents Game Over once per round by covering the basic bet amount if you go bankrupt.",B.e,"\u8a72\u5f53\u30e9\u30a6\u30f3\u30c9\u3067\u7834\u7523(\u8cc7\u91d1\u4e0d\u8db3)\u3057\u305f\u969b\u30011\u56de\u3060\u3051\u57fa\u672c\u8ced\u3051\u91d1\u3092\u30ab\u30d0\u30fc\u3057\u3001\u30b2\u30fc\u30e0\u30aa\u30fc\u30d0\u30fc\u3092\u9632\u304e\u3057\u307e\u3059\u3002",B.f,"\u5728\u8be5\u56de\u5408\u7834\u4ea7\u65f6\uff0c\u4ec5\u9650\u4e00\u6b21\u4e3a\u4f60\u57ab\u4ed8\u57fa\u7840\u8d4c\u6ce8\uff0c\u9632\u6b62\u6e38\u620f\u7ed3\u675f\u3002",B.h,"\u5728\u8a72\u56de\u5408\u7834\u7834\u6642\uff0c\u50c5\u9650\u4e00\u6b21\u70ba\u4f60\u588a\u4ed8\u57fa\u790e\u8ced\u6ce8\uff0c\u9632\u6b62\u904a\u6232\u7d50\u675f\u3002",B.i,"Previene el Game Over una vez por ronda cubriendo la apuesta b\xe1sica si te arruinas.",B.j,"Emp\xeache le Game Over une fois par manche en couvrant la mise de base en cas de faillite.",B.k,"Verhindert einmal pro Runde das Game Over, indem der Grundeinsatz abgedeckt wird, wenn du bankrott gehst.",B.l,"Previne Game Over uma vez por rodada cobrindo a aposta b\xe1sica se voc\xea falir.",B.m,"\u0e1b\u0e49\u0e2d\u0e07\u0e01\u0e31\u0e19 Game Over \u0e2b\u0e19\u0e36\u0e48\u0e07\u0e04\u0e23\u0e31\u0e49\u0e07\u0e15\u0e48\u0e2d\u0e23\u0e2d\u0e1a\u0e42\u0e14\u0e22\u0e08\u0e48\u0e32\u0e22\u0e40\u0e07\u0e34\u0e19\u0e40\u0e14\u0e34\u0e21\u0e1e\u0e31\u0e19\u0e1e\u0e37\u0e49\u0e19\u0e10\u0e32\u0e19\u0e2b\u0e32\u0e01\u0e04\u0e38\u0e13\u0e25\u0e49\u0e21\u0e25\u0e30\u0e25\u0e32\u0e22"],t.C)
B.alv=new A.l([B.d,"A high-risk, high-return item that multiplies your final score by 5 times if you win the round.",B.e,"\u30e9\u30a6\u30f3\u30c9\u52dd\u5229\u6642\u306b\u3001\u6700\u7d42\u30b9\u30b3\u30a2\u3092\u7121\u6761\u4ef6\u306b5\u500d\u306b\u3059\u308b\u30cf\u30a4\u30ea\u30b9\u30af\u30cf\u30a4\u30ea\u30bf\u30fc\u30f3\u30a2\u30a4\u30c6\u30e0\u3002",B.f,"\u9ad8\u98ce\u9669\u9ad8\u56de\u62a5\u7684\u6d88\u8017\u54c1\uff0c\u83b7\u80dc\u65f6\u76f4\u63a5\u5c06\u6700\u7ec8\u5f97\u5206\u4e58\u4ee55\u500d\u3002",B.h,"\u9ad8\u98a8\u96aa\u9ad8\u56de\u5831\u7684\u6d88\u8017\u54c1\uff0c\u7372\u52dd\u6642\u76f4\u63a5\u5c07\u6700\u7d42\u5f97\u5206\u4e58\u4ee55\u500d\u3002",B.i,"Un objeto de alto riesgo y alta recompensa que multiplica tu puntuaci\xf3n final por 5 si ganas la ronda.",B.j,"Un objet \xe0 haut risque et haute r\xe9compense qui multiplie votre score final par 5 si vous gagnez la manche.",B.k,"Ein Hochrisiko-Gegenstand, der deine Endpunktzahl bei Rundengewinn mit 5 multipliziert.",B.l,"Um item de alto risco e alta recompensa que multiplica sua pontua\xe7\xe3o final por 5 se vencer a rodada.",B.m,"\u0e44\u0e2d\u0e40\u0e17\u0e21\u0e40\u0e2a\u0e35\u0e48\u0e22\u0e07\u0e2a\u0e39\u0e07\u0e1c\u0e25\u0e15\u0e2d\u0e1a\u0e41\u0e17\u0e19\u0e2a\u0e39\u0e07 \u0e04\u0e39\u0e13\u0e04\u0e30\u0e41\u0e19\u0e19\u0e2a\u0e38\u0e14\u0e17\u0e49\u0e32\u0e22 5 \u0e40\u0e17\u0e48\u0e32\u0e2b\u0e32\u0e01\u0e0a\u0e19\u0e30\u0e23\u0e2d\u0e1a"],t.C)
B.akh=new A.l([B.d,"Adds an extra 0.5x to 2x multiplier when you declare 3 Go or more.",B.e,"\u30b2\u30fc\u30e0\u4e2d\u30013Go\u4ee5\u4e0a\u3092\u5ba3\u8a00\u3057\u305f\u5834\u5408\u3001\u6700\u7d42\u500d\u7387\u306b0.5\u500d\u301c2\u500d\u3092\u8ffd\u52a0\u3057\u307e\u3059\u3002",B.f,"\u5ba3\u544a 3 Go \u4ee5\u4e0a\u65f6\uff0c\u6700\u7ec8\u500d\u7387\u4f1a\u968f\u673a\u989d\u5916\u589e\u52a0 0.5 \u5230 2 \u500d\u3002",B.h,"\u5ba3\u544a 3 Go \u4ee5\u4e0a\u6642\uff0c\u6700\u7d42\u500d\u7387\u6703\u96a8\u6a5f\u984d\u5916\u589e\u52a0 0.5 \u5230 2 \u500d\u3002",B.i,"Agrega un multiplicador extra de 0.5x a 2x al declarar 3 Go o m\xe1s.",B.j,"Ajoute un multiplicateur suppl\xe9mentaire de 0,5x \xe0 2x lorsque vous d\xe9clarez 3 Go ou plus.",B.k,"F\xfcgt einen zus\xe4tzlichen 0,5x bis 2x Multiplikator hinzu, wenn du 3 Go oder mehr erkl\xe4rst.",B.l,"Adiciona um multiplicador extra de 0,5x a 2x ao declarar 3 Go ou mais.",B.m,"\u0e40\u0e1e\u0e34\u0e48\u0e21\u0e15\u0e31\u0e27\u0e04\u0e39\u0e13\u0e1e\u0e34\u0e40\u0e28\u0e29 0.5x \u0e16\u0e36\u0e07 2x \u0e40\u0e21\u0e37\u0e48\u0e2d\u0e1b\u0e23\u0e30\u0e01\u0e32\u0e28 3 Go \u0e02\u0e36\u0e49\u0e19\u0e44\u0e1b"],t.C)
B.alt=new A.l([B.d,"Defends once against the opponent capturing your cards when you make a Ppeok (Bomb-fail).",B.e,"\u30d7\u30ec\u30a4\u30e4\u30fc\u304c\u30b7\u30e7\u30f3\u3092\u51fa\u3057\u305f\u6642\u3001\u76f8\u624b\u304c\u305d\u306e\u30ab\u30fc\u30c9\u3092\u98df\u3079\u308b\u306e\u3092\u6700\u521d\u306e1\u56de\u3060\u3051\u9632\u304e\u307e\u3059\u3002",B.f,"\u5f53\u4f60\u6253\u51fa\u7206\uff08Ppeok\uff09\u65f6\uff0c\u9996\u6b21\u9632\u5fa1\u5bf9\u624b\u5c06\u5176\u5403\u6389\u3002",B.h,"\u7576\u4f60\u6253\u51fa\u7206\uff08Ppeok\uff09\u6642\uff0c\u9996\u6b21\u9632\u79a6\u5c0d\u624b\u5c07\u5176\u5403\u6389\u3002",B.i,"Defiende una vez cuando el oponente intenta capturar tus cartas al hacer Ppeok (fallo de bomba).",B.j,"Defend une fois contre la capture de vos cartes par l'adversaire lors d'un Ppeok (echec de bombe).",B.k,"Verteidigt einmal dagegen, dass der Gegner deine Karten bei einem Ppeok (Bombenfehler) einfangt.",B.l,"Defende uma vez contra o oponente capturar suas cartas quando voce faz um Ppeok (falha de bomba).",B.m,"\u0e1b\u0e49\u0e2d\u0e07\u0e01\u0e31\u0e19\u0e2b\u0e19\u0e36\u0e48\u0e07\u0e04\u0e23\u0e31\u0e49\u0e07\u0e40\u0e21\u0e37\u0e48\u0e2d\u0e04\u0e39\u0e48\u0e15\u0e48\u0e2d\u0e2a\u0e39\u0e49\u0e1e\u0e22\u0e32\u0e22\u0e32\u0e21\u0e22\u0e36\u0e14\u0e44\u0e1e\u0e48\u0e02\u0e2d\u0e07\u0e04\u0e38\u0e13\u0e15\u0e2d\u0e19\u0e17\u0e33\u0e1b\u0e2d\u0e01 (\u0e23\u0e30\u0e40\u0e1a\u0e34\u0e14\u0e1e\u0e25\u0e32\u0e14)"],t.C)
