B.S2=s(["\xa1\xa1\xa1Buuu!!! \xa1\xa1\xa1Es una bomba!!!","\xa1\xa1Explosi\xf3n de esp\xedritus vengativos!!"],t.s)
B.Xz=s(["Jejeje... \xa1Go!","No ha terminado... Hasta el final del infierno..."],t.s)
B.adH=s(["Jeje... Suficiente.","Ya te he encadenado bastante..."],t.s)
B.a7O=s(["\xa1\xa1\xa1Jajajaja!!! \xa1Mi victoria!","Cosechar\xe9 tu alma..."],t.s)
B.Xu=s(["Ooo... Desvaneci\xe9ndome...","\xbf\xa1Me est\xe1s diciendo que pase al otro lado?!"],t.s)
B.T5=s(["\xa1\xa1Kyaaaaak!! \xa1Me robaron el alma!","\xa1Qu\xe9 rencor...!"],t.s)
B.a0i=s(["\xa1Urgh...! \xbf\xa1Una bomba de exorcismo?!","\xa1Mi forma se desmorona...!"],t.s)
B.SL=s(["Ho-oh... \xbfMe seguir\xe1s al infierno?","No temas la maldici\xf3n..."],t.s)
B.Mz=s(["Ugh... \xa1Este tipo es un demonio!","\xa1Huele a agua bendita...! \xa1Huyan!","Atrapa fantasmas, tiemblo...!"],t.s)
B.a5h=s(["\xa1\xa1Hasta la apuesta de mi alma fue robada!!","M\xe1s t\xf3xico que la parca..."],t.s)
B.aff=s(["Jeje... Apenas salvaste tu hilo de vida.","Tipo ins\xedpido..."],t.s)
B.a89=s(["...Buena intuici\xf3n.","Nada mal..."],t.s)
B.YW=s(["\xa1Jejejek! \xa1Golpeaste el aire!","\xa1Atrapaste el viento!"],t.s)
B.aiK=new A.N(B.x,[B.aeO,B.RA,B.S2,B.Xz,B.adH,B.a7O,B.Xu,B.T5,B.a0i,B.SL,B.Mz,B.a5h,B.aff,B.a89,B.YW],t.M)
B.Un=s(["...Una cosecha.","La guada\xf1a de la muerte pasa.","El registro est\xe1 escrito."],t.s)
B.ac5=s(["No... es el momento a\xfan.","...","Se escap\xf3."],t.s)
B.a88=s(["Bomba del inframundo...!","Llev\xe1ndolo todo... \xa1A cenizas!"],t.s)
B.WA=s(["Go... La muerte espera.","A\xfan no... Hasta ahogar tu \xfaltimo aliento."],t.s)
B.afk=s(["Es suficiente... Te llevar\xe9 la pr\xf3xima vez.","Tu vida se ha extendido."],t.s)
B.aaY=s(["Era tu destino...","Nos vemos en el inframundo..."],t.s)
B.af2=s(["Hmph... Solo esta vez.","La muerte... Nunca pierde. Volver\xe9."],t.s)
B.a4Q=s(["...\xa1Mi bot\xedn!","\xa1Insecto mortal!"],t.s)
B.a4r=s(["\xa1Ugh...! \xa1Burl\xe1ndote de la Parca!","\xa1El m\xe1s all\xe1 tiembla...!"],t.s)
B.abf=s(["Hmph, acortando tu propia vida.","Pasos hacia la muerte..."],t.s)
B.a6b=s(["\xa1E-esto no est\xe1 en el registro de la Parca!","\xbf\xa1Intentando cosecharme a m\xed?!","L-locura total..."],t.s)
B.a1V=s(["Mi l\xe1mpara de vida parpadea...","Maldito demonio..."],t.s)
B.a9Y=s(["...Hmph, vida de rata.","Suplicando por tu vida con solo eso."],t.s)
B.aaM=s(["...\xbfLeyendo el destino?","Ojos agudos."],t.s)
B.a4E=s(["...\xbfNo puedes ver la sombra de la muerte?","Insensato."],t.s)
B.aiI=new A.N(B.x,[B.Un,B.ac5,B.a88,B.WA,B.afk,B.aaY,B.af2,B.a4Q,B.a4r,B.abf,B.a6b,B.a1V,B.a9Y,B.aaM,B.a4E],t.M)
B.a6o=s(["Ya lo vi...","Como fue profetizado...","La luz estelar lo alcanz\xf3."],t.s)
B.a1w=s(["El futuro... est\xe1 temblando.","Esto tambi\xe9n es destino...","Las estrellas est\xe1n ocultas por nubes."],t.s)
B.Yk=s(["\xa1\xa1\xa1La ira del or\xe1culo!!!","\xa1Bomba del destino!"],t.s)
B.St=s(["El or\xe1culo dice... \xa1Go!","A\xfan no es el final, las estrellas lo quieren."],t.s)
B.a4T=s(["Las estrellas me dicen que pare.","Tu destino termina aqu\xed... por ahora."],t.s)
B.Tf=s(["Exactamente como fue profetizado~","La voluntad de las estrellas."],t.s)
B.a9j=s(["\xbf\xa1El futuro... cambi\xf3?!","\xa1Esto no puede ser...! \xa1Un resultado que no est\xe1 en el libro de profec\xedas!"],t.s)
B.a2H=s(["\xa1Ah! \xa1Los engranajes del destino...!","\xa1Mi velo de luz estelar fue levantado!"],t.s)
B.W0=s(["\xa1\xa1Kyaaak!! \xa1La profec\xeda fall\xf3!","\xa1Un choque masivo de destinos...!"],t.s)
B.a8Z=s(["Pretendes forjar tu propio futuro...","Las estrellas est\xe1n observando."],t.s)
B.VQ=s(["\xa1E-esto va m\xe1s all\xe1 de la profec\xeda...!","\xa1El hilo del destino se rompi\xf3...!","Una ruina aterradora se acerca..."],t.s)
B.XX=s(["Mi poder divino... se desvanece...","\xa1La profec\xeda de cat\xe1strofe era cierta!"],t.s)
B.a3k=s(["Parece que solo robaste un poco de destino.","Las estrellas est\xe1n aliviadas."],t.s)
B.MP=s(["\xbfEspiaste el futuro?","Excelente intuici\xf3n."],t.s)
B.Pz=s(["El destino no se ve tan f\xe1cilmente~","La luz estelar se burla de ti."],t.s)
B.ail=new A.N(B.x,[B.a6o,B.a1w,B.Yk,B.St,B.a4T,B.Tf,B.a9j,B.a2H,B.W0,B.a8Z,B.VQ,B.XX,B.a3k,B.MP,B.Pz],t.M)
B.a3u=s(["\xa1Jajaja! \xa1Por supuesto!","\xa1El toque de un dios!","\xa1El universo me ayuda!"],t.s)
B.Qo=s(["Hmph... Fall\xe9 por diversi\xf3n.","...","Piedad para un mortal."],t.s)
B.aeE=s(["\xa1\xa1\xa1Castigo divino!!!","\xa1\xa1\xa1El universo explota!!! \xa1Autoridad divina!"],t.s)
B.S_=s(["\xa1\xa1\xa1Go!!! \xa1El dios nunca se detiene!","\xa1Victoria sin fin! \xa1Infinito!"],t.s)
B.a2Y=s(["Es suficiente... Por hoy.","\xa1Te conceder\xe9 piedad. Stop!"],t.s)
B.Po=s(["\xa1Jajaja! \xbf\xa1Desafiar a un dios?!","\xa1Un resultado natural! \xa1La providencia del universo!"],t.s)
B.ZL=s(["Esto... \xa1\xa1Imposible...!!","\xbf\xa1Qui\xe9n... qui\xe9n eres?! \xbf\xa1Un bug?!"],t.s)
B.SA=s(["\xa1Ugh! \xa1Tomando el milagro de un dios!","\xa1\xa1Buuuuug!!"],t.s)
B.aa3=s(["\xa1\xa1Los cielos se derrumban!!","\xa1\xa1\xa1B-bug!!! \xa1Burl\xe1ndose de un dios!"],t.s)
B.Xe=s(["Ho-oh~ \xa1Luchas bastante bien!","\xbfProbando la paciencia de un dios?"],t.s)
B.Y9=s(["E-esto es capacidad humana...","\xa1M-mi c\xf3digo se enreda!!","\xa1Por favor perd\xf3name! \xa1\xa1\xa1Me degradar\xe1n de la divinidad!!!"],t.s)
B.Ph=s(["El reino divino est\xe1 en bancarrota...","\xbf\xa1Usaste un truco, verdad?! \xa1\xa1Te banear\xe9!!"],t.s)
B.a80=s(["\xa1Jaja! \xa1Intentando vencer a un dios con solo eso!","\xa1Una victoria trivial!"],t.s)
B.Vk=s(["...\xbfDestino retorcido?","Un mono bastante inteligente."],t.s)
B.a2M=s(["\xa1Jajaja! \xa1El l\xedmite de un mortal!","\xa1Ca\xedste en mi cortina de humo divina!"],t.s)
B.a76=s(["\xa1Jajaja! \xa1Pat\xe9tico no tener Gwang! \xa1Mortal!"],t.s)
